38	const DEFAULT_CODE_DISPLAY: CodeDisplayMode = 'masked_with_reveal';
39	
40	/** Internal interface for lock sync status display */
41	interface LockSyncStatus {
42	    /** Current code on the lock (actual or masked) */
43	    code: string | null;
44	    /** Code length when masked */
45	    codeLength?: number;
46	    entityId: string;
