53	    syncStatus?: string;
54	}
55	
56	/** Maps editable field names to their entity key, HA service, and value transform. */
57	const EDIT_FIELD_CONFIG: Record<
58	    'name' | 'pin' | 'numberOfUses',
59	    {
60	        entityKey: keyof NonNullable<SlotCardData['entities']>;
61	        service: string;
62	        serviceData: (v: string) => Record<string, unknown>;
63	    }
64	> = {
65	    name: {
66	        entityKey: 'name',
67	        service: 'text.set_value',
68	        serviceData: (v) => {
69	            return { value: v.trim() };
70	        }
71	    },
72	    numberOfUses: {
73	        entityKey: 'number_of_uses',
74	        service: 'number.set_value',
75	        serviceData: (v) => {
76	            const num = parseInt(v, 10);
77	            return !isNaN(num) && num >= 0 ? { value: num } : {};
78	        }
79	    },
80	    pin: {
81	        entityKey: 'pin',
82	        service: 'text.set_value',
83	        serviceData: (v) => {
84	            return { value: v.trim() };
85	        }
86	    }
87	};
