89	// Base class with subscription mixin
90	const LcmSlotCardBase = LcmSubscriptionMixin(LitElement);
91	
92	/**
93	 * Streamlined slot card for Lock Code Manager.
94	 *
95	 * Phase 3: Uses websocket subscription for real-time updates.
96	 */
97	class LockCodeManagerSlotCard extends LcmSlotCardBase {
98	    static styles = slotCardStyles;
99	
100	    // Note: _revealed, _unsub, _subscribing provided by LcmSubscriptionMixin
101	    @state() _config?: LockCodeManagerSlotCardConfig;
102	    @state() _data?: SlotCardData;
103	    @state() _error?: string;
104	    @state() private _actionError?: string;
105	    @state() private _conditionsExpanded = false;
106	    @state() private _editingField: 'name' | 'pin' | 'numberOfUses' | null = null;
107	    @state() private _lockStatusExpanded = false;
108	
109	    // Condition dialog state
110	    @state() private _showConditionDialog = false;
111	    @state() private _dialogMode: 'add-entity' | 'edit-entity' = 'add-entity';
112	    @state() private _dialogEntityId: string | null = null;
113	    @state() private _dialogSaving = false;
114	
115	    // Confirmation dialog state
116	    @state() private _confirmDialog: {
117	        onConfirm: () => void;
118	        text: string;
119	        title: string;
120	    } | null = null;
121	
122	    _hass?: HomeAssistant;
123	    private _entityRowCache = new Map<string, HTMLElement>();
124	
125	    get hass(): HomeAssistant | undefined {
126	        return this._hass;
127	    }
128	
129	    @property({ attribute: false })
130	    set hass(hass: HomeAssistant) {
131	        this._hass = hass;
132	        void this._subscribe();
133	    }
134	
135	    static getConfigElement(): HTMLElement {
136	        return document.createElement('lcm-slot-editor');
137	    }
138	
139	    static async getStubConfig(hass: HomeAssistant): Promise<Record<string, unknown>> {
140	        const stub = { config_entry_id: 'stub', slot: 1, type: 'custom:lcm-slot' };
141	        try {
142	            return await Promise.race([
143	                (async () => {
144	                    const entries = await hass.callWS<GetConfigEntriesResponse>({
145	                        domain: 'lock_code_manager',
146	                        type: 'config_entries/get'
147	                    });
148	                    if (entries.length > 0) {
149	                        return {
150	                            config_entry_id: entries[0].entry_id,
151	                            slot: 1,
152	                            type: 'custom:lcm-slot'
153	                        };
154	                    }
155	                    return stub;
156	                })(),
157	                new Promise<Record<string, unknown>>((resolve) =>
158	                    setTimeout(() => resolve(stub), 2000)
159	                )
160	            ]);
161	        } catch {
162	            return stub;
163	        }
164	    }
165	
166	    setConfig(config: LockCodeManagerSlotCardConfig): void {
167	        if (!config.config_entry_id && !config.config_entry_title) {
168	            throw new Error('config_entry_id or config_entry_title is required');
169	        }
170	        if (typeof config.slot !== 'number' || config.slot < 1 || config.slot > 9999) {
171	            throw new Error('slot must be a number between 1 and 9999');
172	        }
173	        // If config changed, unsubscribe and resubscribe
174	        if (
175	            this._config?.config_entry_id !== config.config_entry_id ||
176	            this._config?.config_entry_title !== config.config_entry_title ||
177	            this._config?.slot !== config.slot
178	        ) {
179	            this._unsubscribe();
180	            this._data = undefined;
181	        }
182	        this._config = config;
183	
184	        // Set initial collapsed state from config
185	        const collapsed = config.collapsed_sections ?? ['conditions', 'lock_status'];
186	        this._conditionsExpanded = !collapsed.includes('conditions');
187	        this._lockStatusExpanded = !collapsed.includes('lock_status');
188	        this._isStub = config.config_entry_id === 'stub';
189	        if (!this._isStub) {
190	            void this._subscribe();
191	        }
192	    }
193	
194	    // Mixin abstract method implementations
195	    protected _getDefaultCodeDisplay(): CodeDisplayMode {
196	        return DEFAULT_CODE_DISPLAY;
197	    }
198	
199	    protected _buildSubscribeMessage(): MessageBase {
200	        if (!this._config) {
201	            throw new Error('Config not set');
202	        }
203	        const msg: MessageBase & {
204	            config_entry_id?: string;
205	            config_entry_title?: string;
206	            reveal: boolean;
207	            slot: number;
208	        } = {
209	            reveal: this._shouldReveal(),
210	            slot: this._config.slot,
211	            type: 'lock_code_manager/subscribe_code_slot'
212	        };
213	        if (this._config.config_entry_id) {
214	            msg.config_entry_id = this._config.config_entry_id;
215	        } else if (this._config.config_entry_title) {
216	            msg.config_entry_title = this._config.config_entry_title;
217	        }
218	        return msg;
219	    }
220	
221	    protected _handleSubscriptionData(data: unknown): void {
222	        this._data = data as SlotCardData;
223	    }
224	
225	    // connectedCallback and disconnectedCallback provided by mixin
226	
227	    protected updated(changedProperties: Map<string, unknown>): void {
228	        super.updated(changedProperties);
229	
230	        // Focus the appropriate input when entering edit mode
231	        if (this._editingField) {
232	            const selectors: Record<string, string> = {
233	                name: '.control-row .edit-input.name-edit-input',
234	                numberOfUses: '.condition-row .edit-input[type="number"]',
235	                pin: '.pin-edit-input'
236	            };
237	            const input = this.shadowRoot?.querySelector<HTMLInputElement>(
238	                selectors[this._editingField]
239	            );
240	            if (input && this.shadowRoot?.activeElement !== input) {
241	                input.focus();
242	                input.select();
243	            }
244	        }
245	    }
246	
247	    protected render(): TemplateResult {
248	        if (!this._hass || !this._config) {
249	            return html`<ha-card><div class="message">Loading...</div></ha-card>`;
250	        }
251	
252	        // Show static preview for card picker (stub config)
253	        if (this._isStub) {
254	            return html`<ha-card>
255	                <div class="message">Lock Code Manager Slot Card</div>
256	            </ha-card>`;
257	        }
258	
259	        if (this._error) {
260	            return html`<ha-card>
261	                <div class="message error">${this._error}</div>
262	            </ha-card>`;
263	        }
264	
265	        // Use websocket data if available
266	        if (this._data) {
267	            return this._renderFromData(this._data);
268	        }
269	
270	        // Fallback to state-based approach (initial load before subscription)
271	        return html`<ha-card><div class="message">Connecting...</div></ha-card>`;
272	    }
273	
274	    private _renderFromData(data: SlotCardData): TemplateResult {
275	        const mode = this._config?.code_display ?? DEFAULT_CODE_DISPLAY;
276	        const { name, pin, enabled, active, conditions, locks } = data;
277	        const pinLength = data.pin_length;
278	
279	        // Transform locks to the expected format
280	        const lockStatuses = locks.map((lock) => {
281	            return {
282	                code: lock.code,
283	                codeLength: lock.code_length,
284	                entityId: lock.entity_id,
285	                inSync: lock.in_sync,
286	                lastSynced: lock.last_synced,
287	                lockEntityId: lock.entity_id,
288	                name: lock.name,
289	                syncStatus: lock.sync_status
290	            };
291	        });
292	
293	        const showLockStatus = this._config.show_lock_status !== false;
294	
295	        // Only show conditions section if at least one condition is configured
296	        const hasConditionHelpers =
297	            (this._config?.condition_helpers?.length ?? 0) > 0 &&
298	            this._config!.condition_helpers!.some((eid: string) => this._hass?.states[eid]);
299	        const hasConditions =
300	            (conditions.number_of_uses !== undefined && conditions.number_of_uses !== null) ||
301	            conditions.condition_entity !== undefined ||
302	            conditions.calendar !== undefined ||
303	            hasConditionHelpers;
304	        const showConditions = this._config.show_conditions !== false && hasConditions;
305	        // Show "Manage Conditions" row when no conditions exist
306	        const showManageConditions = this._config.show_conditions !== false && !hasConditions;
307	
308	        return html`
309	            <ha-card>
310	                ${this._actionError
311	                    ? html`<div class="action-error">
312	                          <span>${this._actionError}</span>
313	                          <button
314	                              class="action-error-dismiss"
315	                              @click=${this._dismissActionError}
316	                              aria-label="Dismiss error"
317	                          >
318	                              ✕
319	                          </button>
320	                      </div>`
321	                    : nothing}
322	                ${this._renderHeader()}
323	                <div class="content">
324	                    ${this._renderPrimaryControls(name, pin, pinLength, enabled, mode)}
325	                    ${this._renderStatus(enabled, active)}
326	                    ${showManageConditions ? this._renderManageConditionsRow() : nothing}
327	                    ${showConditions ? this._renderConditionsSection(conditions) : nothing}
328	                    ${showLockStatus ? this._renderLockStatusSection(lockStatuses) : nothing}
329	                </div>
330	                ${this._showConditionDialog ? this._renderConditionDialog() : nothing}
331	                ${this._confirmDialog ? this._renderConfirmDialog() : nothing}
332	            </ha-card>
333	        `;
334	    }
335	
336	    private _renderHeader(): TemplateResult {
337	        const lockCount = this._data?.locks?.length ?? 0;
338	        const showLockCount = this._config?.show_lock_count !== false;
339	        const lastUsed = this._data?.last_used;
340	        const eventEntityId = this._data?.event_entity_id;
341	        const eventEntityState = eventEntityId ? this._hass?.states[eventEntityId] : undefined;
342	        const showLastUsed = eventEntityState && eventEntityState.state !== 'unavailable';
343	
344	        const showPills = (showLockCount && lockCount > 0) || showLastUsed;
345	
346	        return html`
347	            <div class="header">
348	                <div class="header-top">
349	                    <div class="header-icon">
350	                        <ha-svg-icon .path=${mdiKey}></ha-svg-icon>
351	                    </div>
352	                    <div class="header-info">
353	                        <span class="header-title">Code Slot ${this._config?.slot}</span>
354	                    </div>
355	                    ${showPills
356	                        ? html`<div class="header-pills">
357	                              ${showLockCount && lockCount > 0
358	                                  ? html`<span
359	                                        class="header-pill clickable"
360	                                        title=${this._data?.locks?.map((l) => l.name).join(', ') ??
