362	                                        @click=${this._toggleLockStatus}
363	                                    >
364	                                        <ha-svg-icon .path=${mdiLock}></ha-svg-icon>
365	                                        ${lockCount}
366	                                    </span>`
367	                                  : nothing}
368	                              ${showLastUsed
369	                                  ? html`<span
370	                                        class="header-pill ${lastUsed ? 'clickable' : ''}"
371	                                        title=${lastUsed
372	                                            ? this._data?.last_used_lock
373	                                                ? `Used on ${this._data.last_used_lock} - Click for details`
374	                                                : 'Click for PIN usage details'
375	                                            : 'This PIN has never been used'}
376	                                        @click=${() => lastUsed && this._navigateToEventHistory()}
377	                                    >
378	                                        <ha-svg-icon .path=${mdiClock}></ha-svg-icon>
379	                                        ${lastUsed
380	                                            ? html`${this._data?.last_used_lock ?? 'Used'}
381	                                                  <ha-relative-time
382	                                                      .hass=${this._hass}
383	                                                      .datetime=${lastUsed}
384	                                                  ></ha-relative-time>`
385	                                            : 'Never used'}
386	                                    </span>`
387	                                  : nothing}
388	                          </div>`
389	                        : nothing}
390	                </div>
391	            </div>
392	        `;
393	    }
394	
395	    private _navigateToEventHistory(): void {
396	        const eventEntityId = this._data?.event_entity_id;
397	        if (!eventEntityId) return;
398	        // Open the more-info dialog for this event entity
399	        const event = new CustomEvent('hass-more-info', {
400	            bubbles: true,
401	            composed: true,
402	            detail: { entityId: eventEntityId }
