427	                <div class="lcm-section-header">Primary Controls</div>
428	
429	                <div class="control-row">
430	                    <span class="control-label">Name</span>
431	                    <div style="flex: 1;">
432	                        ${this._editingField === 'name'
433	                            ? html`<input
434	                                      class="edit-input name-edit-input"
435	                                      type="text"
436	                                      .value=${name ?? ''}
437	                                      @blur=${this._handleEditBlur}
438	                                      @keydown=${this._handleEditKeydown}
439	                                  />
440	                                  <div class="edit-help">Enter to save, Esc to cancel</div>`
441	                            : html`<span
442	                                  class="control-value editable"
443	                                  @click=${() => this._startEditing('name')}
444	                              >
445	                                  ${name || html`<em class="placeholder">&lt;No Name&gt;</em>`}
446	                              </span>`}
447	                    </div>
448	                </div>
449	
450	                <div class="control-row">
451	                    <span class="control-label">PIN</span>
452	                    <div style="flex: 1;">
453	                        <div class="pin-field">
454	                            ${this._editingField === 'pin'
455	                                ? html`<input
456	                                      class="edit-input pin-edit-input"
457	                                      type="text"
458	                                      inputmode="numeric"
459	                                      pattern="[0-9]*"
460	                                      .value=${pin ?? ''}
461	                                      @blur=${this._handleEditBlur}
462	                                      @keydown=${this._handleEditKeydown}
463	                                  />`
464	                                : html`<span
465	                                      class="pin-value editable ${shouldMask && hasPin
466	                                          ? 'masked'
467	                                          : ''}"
468	                                      @click=${() => this._startEditing('pin')}
469	                                  >
470	                                      ${displayPin ??
471	                                      html`<em class="placeholder">&lt;No PIN&gt;</em>`}
472	                                  </span>`}
473	                            ${mode === 'masked_with_reveal' &&
474	                            hasPin &&
475	                            this._editingField !== 'pin'
476	                                ? html`<ha-icon-button
477	                                      class="pin-reveal"
478	                                      .path=${this._revealed ? mdiEyeOff : mdiEye}
479	                                      @click=${this._toggleReveal}
480	                                      .label=${this._revealed ? 'Hide PIN' : 'Reveal PIN'}
481	                                  ></ha-icon-button>`
482	                                : nothing}
483	                        </div>
484	                        ${this._editingField === 'pin'
485	                            ? html`<div class="edit-help">Enter to save, Esc to cancel</div>`
486	                            : nothing}
487	                    </div>
488	                </div>
