714	    /**
715	     * Format a schedule date for display (today, tomorrow, or weekday).
716	     * Returns empty string for today, "tomorrow " or "Mon " etc for other days.
717	     */
718	    private _formatScheduleDate(date: Date): string {
719	        const now = new Date();
720	        const isToday = date.toDateString() === now.toDateString();
721	        if (isToday) return '';
722	
723	        const tomorrow = new Date(now);
724	        tomorrow.setDate(tomorrow.getDate() + 1);
725	        const isTomorrow = date.toDateString() === tomorrow.toDateString();
726	        if (isTomorrow) return 'tomorrow ';
727	
728	        return `${date.toLocaleDateString([], { weekday: 'short' })} `;
729	    }
