745	    /**
746	     * Render a unified condition entity display.
747	     * Consistent structure across all domain types with domain-specific context.
748	     */
749	    private async _getEntityRow(entityId: string): Promise<HTMLElement> {
750	        const cached = this._entityRowCache.get(entityId);
751	        if (cached) {
752	            // eslint-disable-next-line @typescript-eslint/no-explicit-any
753	            (cached as any).hass = this._hass;
754	            return cached;
755	        }
756	
757	        // Use HA's loadCardHelpers to get createRowElement, which handles
758	        // lazy-loading and domain-to-row mapping automatically
759	        // eslint-disable-next-line @typescript-eslint/no-explicit-any
760	        const loadHelpers = (window as any).loadCardHelpers;
761	        if (!loadHelpers) {
762	            const fallback = document.createElement('div');
763	            fallback.textContent = entityId;
764	            return fallback;
765	        }
766	        const helpers = await loadHelpers();
767	        const el = helpers.createRowElement({ entity: entityId }) as HTMLElement;
768	        // eslint-disable-next-line @typescript-eslint/no-explicit-any
769	        (el as any).hass = this._hass;
770	        this._entityRowCache.set(entityId, el);
771	        return el;
772	    }
