939	    private _renderLockRow(lock: LockSyncStatus): TemplateResult {
940	        const showSync = this._config?.show_lock_sync !== false;
941	        const showCodeSensors = this._config?.show_code_sensors !== false;
942	        const mode = this._config?.code_display ?? DEFAULT_CODE_DISPLAY;
943	        const showRevealButton = showCodeSensors && mode === 'masked_with_reveal';
944	
945	        let iconClass: string;
946	        let statusText: string;
947	        let icon: string;
948	
949	        switch (lock.syncStatus) {
950	            case 'in_sync':
951	                iconClass = 'synced';
952	                statusText = 'Synced';
953	                icon = 'mdi:check-circle';
954	                break;
955	            case 'out_of_sync':
956	                iconClass = 'pending';
957	                statusText = 'Out of sync';
958	                icon = 'mdi:clock-outline';
959	                break;
960	            case 'syncing':
961	                iconClass = 'syncing';
962	                statusText = 'Syncing';
963	                icon = 'mdi:sync';
964	                break;
965	            case 'suspended':
966	                iconClass = 'suspended';
967	                statusText = 'Suspended';
968	                icon = 'mdi:alert-circle';
969	                break;
970	            default:
971	                // Fallback for when sync_status is not available
972	                if (lock.inSync === true) {
973	                    iconClass = 'synced';
974	                    statusText = 'Synced';
975	                    icon = 'mdi:check-circle';
976	                } else if (lock.inSync === false) {
977	                    iconClass = 'pending';
978	                    statusText = 'Out of sync';
979	                    icon = 'mdi:clock-outline';
980	                } else {
981	                    iconClass = 'unknown';
982	                    statusText = 'Unknown';
983	                    icon = 'mdi:help-circle';
984	                }
985	        }
986	
987	        // Format code display
988	        const codeDisplay = this._formatLockCode(lock);
989	
990	        return html`
991	            <div class="lock-row">
992	                ${showSync
993	                    ? html`<ha-icon class="lcm-sync-icon ${iconClass}" icon="${icon}"></ha-icon>`
994	                    : nothing}
995	                <div class="lock-info">
996	                    <span
997	                        class="lock-name"
998	                        title="View lock codes"
999	                        @click=${() => this._navigateToLock(lock.lockEntityId)}
1000	                    >
1001	                        ${lock.name}
1002	                    </span>
1003	                    ${showSync && lock.syncStatus !== 'suspended' && lock.lastSynced
1004	                        ? html`<span class="lock-synced-time">
1005	                              Last synced to lock
1006	                              <ha-relative-time
1007	                                  .hass=${this._hass}
1008	                                  .datetime=${lock.lastSynced}
1009	                              ></ha-relative-time>
1010	                          </span>`
1011	                        : showSync
1012	                          ? html`<span class="lock-synced-time ${iconClass}">${statusText}</span>`
1013	                          : nothing}
1014	                </div>
1015	                ${showCodeSensors && codeDisplay
1016	                    ? html`<div class="lock-code-field">
1017	                          <span class="lock-code-value">${codeDisplay}</span>
1018	                          ${showRevealButton
1019	                              ? html`<ha-icon-button
1020	                                    class="lcm-reveal-button"
1021	                                    .path=${this._revealed ? mdiEyeOff : mdiEye}
1022	                                    @click=${this._toggleReveal}
1023	                                    .label=${this._revealed ? 'Hide codes' : 'Reveal codes'}
1024	                                ></ha-icon-button>`
1025	                              : nothing}
1026	                      </div>`
1027	                    : nothing}
1028	            </div>
1029	        `;
1030	    }
1031	
1032	    private _formatLockCode(lock: LockSyncStatus): string | null {
1033	        const mode = this._config?.code_display ?? DEFAULT_CODE_DISPLAY;
1034	        const shouldMask = mode === 'masked' || (mode === 'masked_with_reveal' && !this._revealed);
1035	
1036	        if (isSlotEmpty(lock.code)) return null;
1037	        if (lock.code === SLOT_CODE_UNREADABLE) return '• • •';
1038	        return shouldMask ? '•'.repeat(String(lock.code).length) : String(lock.code);
1039	    }
