file.content:
    min-width: 60px;
}

.control-value {
    align-items: center;
    color: var(--primary-text-color);
    display: flex;
    flex: 1;
    font-family: var(--lcm-code-font);
    font-size: var(--lcm-code-font-size);
    font-weight: var(--lcm-code-font-weight);
    gap: 8px;
    min-height: 1.5em;
}

.placeholder {
    color: var(--secondary-text-color);
    font-style: italic;
}

.pin-field {
    align-items: center;
    display: flex;
    flex: 1;
    gap: 8px;
}

.pin-value {
    font-family: var(--lcm-code-font);
    font-size: var(--lcm-code-font-size);
    font-weight: var(--lcm-code-font-weight);
    letter-spacing: 2px;
    min-height: 1.5em;
}

.pin-value.masked {
    color: var(--secondary-text-color);
}

.pin-reveal {
    --mdc-icon-button-size: 32px;
    --mdc-icon-size: 18px;
}

/* Name-specific edit input (extends shared editable styles) */
.name-edit-input {
    font-family: var(--lcm-code-font);
    font-size: var(--lcm-code-font-size);
    font-weight: var(--lcm-code-font-weight);
}

/* PIN-specific edit input (extends shared editable styles) */
.pin-edit-input {
    font-family: var(--lcm-code-font);
    font-size: var(--lcm-code-font-size);
    font-weight: var(--lcm-code-font-weight);
    letter-spacing: 2px;
}

.enabled-row {
    align-items: center;
    display: flex;
    gap: 16px;
    justify-content: space-between;
}

.enabled-label {
    color: var(--secondary-text-color);
    font-size: 14px;
}

/* Status Section */
.status-row {
    align-items: center;
    display: flex;
    gap: 12px;
}

.status-text {
    color: var(--primary-text-color);
    font-size: 14px;
    font-weight: 500;
}

.status-detail {
    color: var(--secondary-text-color);
    font-size: 13px;
    margin-left: 24px;
    margin-top: 4px;
}

/* Conditions Section */
.condition-row {
    align-items: center;
    display: flex;
    gap: 12px;
    padding: 8px 0;
}

.condition-row:first-child {
    padding-top: 0;
}

.condition-row:last-child {
    padding-bottom: 0;
}

.condition-label {
    color: var(--secondary-text-color);
    font-size: 13px;
    min-width: 100px;
}

.condition-value {
    color: var(--primary-text-color);
    font-size: 14px;
}

/* Unified condition item (matches condition-entity structure) */
.condition-item {
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding: 8px 0;
}

.condition-item-header {
    align-items: center;
    display: flex;
    gap: 8px;
}

.condition-item-detail {
    font-size: 13px;
    margin-left: 28px;
}

/* Inline edit container for number of uses */
.condition-edit-container {
    position: relative;
}

.condition-edit-container .edit-input {
    background: var(--card-background-color);
    border: 1px solid var(--primary-color);
    border-radius: 4px;
    color: var(--primary-text-color);
    font-size: 14px;
    padding: 4px 8px;
    width: 60px;
}

.condition-edit-container .edit-help {
    color: var(--secondary-text-color);
    font-size: 10px;
    left: 0;
    position: absolute;
    top: 100%;
    white-space: nowrap;
}

