/**
 * Styles for the LCM slot card component.
 *
 * Separated from slot-card.ts for readability. Composes shared styles
 * from shared-styles.ts with slot-card-specific layout rules.
 */
import { css } from 'lit';

import {
    lcmCollapsibleStyles,
    lcmCssVars,
    lcmEditableStyles,
    lcmRevealButtonStyles,
    lcmSectionStyles,
    lcmStatusIndicatorStyles
} from './shared-styles';

const slotCardComponentStyles = css`
    :host {
        display: block;
    }

    ha-card {
        overflow: hidden;
    }

    /* Header Section */
    .header {
        background: var(--ha-card-background, var(--card-background-color, #fff));
        border-bottom: 1px solid var(--lcm-border-color);
        display: flex;
        flex-direction: column;
        gap: 12px;
        padding: 16px;
    }

    .header-top {
        align-items: center;
        display: flex;
        flex-wrap: wrap;
        gap: 8px 12px;
    }

    .header-icon {
        align-items: center;
        background: var(--lcm-active-bg);
        border-radius: 50%;
        color: var(--primary-color);
        display: flex;
        flex-shrink: 0;
        height: 40px;
        justify-content: center;
        width: 40px;
    }

    .header-icon ha-svg-icon {
        --mdc-icon-size: 24px;
    }

    .header-info {
        display: flex;
        flex: 1;
        flex-direction: column;
        gap: 2px;
        min-width: 0;
    }

    .header-title {
        color: var(--primary-text-color);
        font-size: 18px;
        font-weight: 500;
        white-space: nowrap;
    }

    .header-pills {
        align-items: center;
        display: flex;
        flex-wrap: wrap;
        gap: 4px;
    }

    .header-pill {
        align-items: center;
        background: var(--lcm-section-bg);
        border-radius: 12px;
        color: var(--secondary-text-color);
        display: flex;
        font-size: 11px;
        gap: 4px;
        max-width: 100%;
        overflow: hidden;
        padding: 4px 8px;
        text-overflow: ellipsis;
        white-space: nowrap;
    }

    .header-pill ha-svg-icon {
        --mdc-icon-size: 14px;
        flex-shrink: 0;
    }

