.dialog-section {
    margin-top: 48px;
    max-width: 500px;
}
.dialog-section h2 {
    color: var(--secondary-text-color);
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.08em;
    margin: 0 0 12px;
    text-transform: uppercase;
}
.dialog-card {
    background: #2b2b2b;
    border-radius: 12px;
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.35);
    overflow: hidden;
}
.dialog-header {
    color: var(--primary-text-color);
    font-size: 18px;
    font-weight: 500;
    padding: 20px 24px 12px;
}
.dialog-body { padding: 0 24px 16px; }
.dialog-description {
    color: var(--secondary-text-color);
    font-size: 13px;
    line-height: 1.5;
    margin: 0 0 16px;
}
.dialog-label {
    color: var(--secondary-text-color);
    display: block;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.04em;
    margin-bottom: 6px;
    text-transform: uppercase;
}
.dialog-input {
    background: #1c1c1c;
    border: 1px solid var(--lcm-border-color);
    border-radius: 6px;
    color: var(--primary-text-color);
    font-family: ui-monospace, SFMono-Regular, monospace;
    font-size: 14px;
    padding: 10px 12px;
    width: 100%;
    box-sizing: border-box;
}
.dialog-help {
    color: var(--disabled-text-color);
    font-size: 11px;
    margin: 6px 0 0;
}
.dialog-footer {
    align-items: center;
    border-top: 1px solid var(--lcm-border-color);
    display: flex;
    gap: 12px;
    padding: 12px 16px;
}
.dialog-spacer { flex: 1; }
.dialog-btn {
    background: transparent;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 500;
    padding: 8px 16px;
}
.dialog-btn.destructive { color: var(--lcm-warning-color); padding-left: 8px; }
.dialog-btn.destructive:hover { background: rgba(239, 83, 80, 0.10); color: var(--lcm-error-color); }
.dialog-btn.secondary { color: var(--secondary-text-color); }
.dialog-btn.secondary:hover { color: var(--primary-text-color); }
.dialog-btn.primary { background: var(--primary-color); color: #fff; }
.dialog-btn.primary:hover { background: #0288d1; }
.dialog-trigger-note {
    color: var(--secondary-text-color);
    font-size: 12px;
    line-height: 1.5;
    margin-top: 12px;
}
.dialog-trigger-note code {
    background: rgba(255, 255, 255, 0.06);
    border-radius: 4px;
    color: var(--primary-text-color);
    font-size: 12px;
    padding: 1px 6px;
}

