"""Repairs for lock_code_manager."""

from __future__ import annotations

from homeassistant import data_entry_flow
from homeassistant.components.repairs import RepairsFlow
from homeassistant.core import HomeAssistant

from .const import CONF_NUMBER_OF_USES, CONF_SLOTS, DOMAIN


class AcknowledgeRepairFlow(RepairsFlow):
    """Simple repair flow that just acknowledges the issue."""

    async def async_step_init(
        self, user_input: dict[str, str] | None = None
    ) -> data_entry_flow.FlowResult:
        """Handle the confirm step."""
        if user_input is not None:
            return self.async_create_entry(title="", data={})
        return self.async_show_form(step_id="init")


class NumberOfUsesDeprecatedFlow(RepairsFlow):
    """
    Handler for the number_of_uses deprecation repair.

    When the user confirms, strips number_of_uses from all slot configs
    in the config entry.
    """

    async def async_step_init(
        self, user_input: dict[str, str] | None = None
    ) -> data_entry_flow.FlowResult:
        """Handle the confirm step."""
        if user_input is not None:
            # Strip number_of_uses from all config entries
            for entry in self.hass.config_entries.async_entries(DOMAIN):
                new_data = {**entry.data}
                new_options = {**entry.options}
                changed = False

                for data_dict in (new_data, new_options):
                    if CONF_SLOTS in data_dict:
                        new_slots = {}
                        for slot_num, slot_config in data_dict[CONF_SLOTS].items():
                            new_slot = {**slot_config}
                            if CONF_NUMBER_OF_USES in new_slot:
                                new_slot.pop(CONF_NUMBER_OF_USES)
                                changed = True
                            new_slots[slot_num] = new_slot
                        data_dict[CONF_SLOTS] = new_slots

                if changed:
                    self.hass.config_entries.async_update_entry(
                        entry, data=new_data, options=new_options
                    )

            return self.async_create_entry(title="", data={})

        return self.async_show_form(step_id="init")


async def async_create_fix_flow(
    hass: HomeAssistant, issue_id: str, data: dict[str, str] | None
) -> RepairsFlow:
    """Create a fix flow for a repair issue."""
    if issue_id == "number_of_uses_deprecated":
        return NumberOfUsesDeprecatedFlow()
    if issue_id.startswith(("slot_disabled_", "pin_required_", "slot_suspended_")):
        return AcknowledgeRepairFlow()
    raise ValueError(f"Unknown issue: {issue_id}")

    manufacturer="Lock Code Manager",
    name=config_entry.title,
    serial_number=entry_id,
)

await hass.config_entries.async_forward_entry_setups(config_entry, PLATFORMS)

# Create or dismiss repair issue based on deprecated number_of_uses presence
# across ALL config entries (not just this one) since the issue is global
has_number_of_uses = any(
    CONF_NUMBER_OF_USES in slot_config
    for entry in hass.config_entries.async_entries(DOMAIN)
    for slot_config in get_entry_config(entry).slots.values()
)
if has_number_of_uses:
    async_create_issue(
        hass,
        DOMAIN,
        "number_of_uses_deprecated",
        is_fixable=True,
        is_persistent=True,
        severity=IssueSeverity.WARNING,
        translation_key="number_of_uses_deprecated",
        translation_placeholders={
            "blueprint_url": "https://github.com/raman325/lock_code_manager/wiki/Blueprints#slot-usage-limiter",
        },
    )
else:
    async_delete_issue(hass, DOMAIN, "number_of_uses_deprecated")

if hass.state == CoreState.running:
    _setup_entry_after_start(hass, config_entry)
else:
    # async_listen_once self-unsubscribes when it fires, so calling
    # unsub() again would error. Track whether it fired so unload only
    # tears down the listener if HA never started before unload.
    started = [False]

    @callback
    def _on_started(event: Event) -> None:
        started[0] = True
        _setup_entry_after_start(hass, config_entry, event)

    unsub = hass.bus.async_listen_once(EVENT_HOMEASSISTANT_STARTED, _on_started)

    @callback
    def _safe_unsub() -> None:
        if not started[0]:
            unsub()

