- [ ] **Step 3: Replace `_renderHeader` body**

In `ts/slot-card.ts`, replace the existing `_renderHeader` method (lines 336–393) with:

```typescript
private _renderHeader(): TemplateResult {
    const slotKicker = this._renderSlotKicker();
    const stateChip = this._renderStateChip();
    const name = this._data?.name;

    return html`
        <div class="header">
            <div class="header-top">
                <span class="slot-kicker">${slotKicker}</span>
                ${stateChip}
            </div>
            <div class="name">
                ${name
                    ? html`${name}`
                    : html`<em class="placeholder">&lt;No Name&gt;</em>`}
                <ha-icon-button
                    class="pencil"
                    .path=${mdiPencil}
                    @click=${() => this._startEditing('name')}
                    .label=${'Edit name'}
                ></ha-icon-button>
            </div>
        </div>
    `;
}

private _renderSlotKicker(): string {
    const slot = this._config?.slot;
    const title = this._configEntryTitle();
    return title ? `Slot ${slot} · ${title}` : `Slot ${slot}`;
}

private _configEntryTitle(): string | undefined {
    // Prefer the explicit config_entry_title from the card config when set.
    // Otherwise look it up from hass.config_entries via config_entry_id.
    if (this._config?.config_entry_title) {
        return this._config.config_entry_title;
    }
    if (this._config?.config_entry_id && this._hass) {
        // hass.config doesn't expose entries directly; fall back to none.
        // The websocket payload also includes the title in some shapes —
        // adopt that field if present.
        return (this._data as { config_entry_title?: string })?.config_entry_title;
    }
    return undefined;
}

private _renderStateChip(): TemplateResult {
    const enabled = this._data?.enabled;
    const active = this._data?.active;
    let cls: 'active' | 'inactive' | 'disabled';
    let text: string;
    if (enabled === false) {
        cls = 'disabled';
        text = 'Disabled by user';
    } else if (active === true) {
        cls = 'active';
        text = 'Active';
    } else if (active === false) {
        cls = 'inactive';
        text = 'Blocked by conditions';
    } else {
        cls = 'disabled';
        text = 'Unknown';
    }
    return html`
        <span class="state-chip ${cls}">
            <span class="dot"></span>${text}
        </span>
    `;
}
```

Notes for the implementor:
- If `config_entry_title` isn't already part of `LockCodeManagerSlotCardConfig` or the websocket payload, add it. Backend likely already exposes the title via `entry.title` — surface it in the slot subscription event in `websocket.py` if missing.
- The pencil button replaces the inline `<span @click>` edit affordance from the old `_renderPrimaryControls`. Make sure `mdiPencil` is in the import list at the top of the file.

