In `ts/slot-card.ts`, delete `_renderPrimaryControls` and add:

```typescript
private _renderHero(
    pin: string | null,
    pinLength: number | undefined,
    enabled: boolean | null,
    mode: CodeDisplayMode
): TemplateResult {
    const shouldMask = mode === 'masked' || (mode === 'masked_with_reveal' && !this._revealed);
    const hasPin = pin !== null || pinLength !== undefined;
    const displayPin = pin
        ? shouldMask
            ? '•'.repeat(pin.length)
            : pin
        : pinLength !== undefined
          ? '•'.repeat(pinLength)
          : null;

    return html`
        <div class="hero">
