}

.add-link {
    color: var(--primary-color);
    cursor: pointer;
    display: inline-block;
    font-size: 12px;
    font-weight: 500;
    margin-top: 6px;
}

.entity-row-loading {
    color: var(--disabled-text-color);
    font-size: 12px;
    padding: 10px 12px;
}

.entity-row-error {
    color: var(--disabled-text-color);
    font-size: 12px;
    font-style: italic;
    padding: 10px 12px;
}

.no-conditions {
    color: var(--secondary-text-color);
    font-size: 13px;
    font-style: italic;
}

/* Lock Status Section */
.lock-row {
    align-items: center;
    border-bottom: 1px solid var(--lcm-border-color);
    display: flex;
    gap: 12px;
    padding: 10px 0;
}

.lock-row:last-child {
    border-bottom: none;
    padding-bottom: 0;
}

.lock-row:first-child {
    padding-top: 0;
}

.lock-name {
    color: var(--primary-text-color);
    cursor: pointer;
    flex: 1;
    font-size: 14px;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.lock-name:hover {
    color: var(--primary-color);
    text-decoration: underline;
}

.lock-info {
    display: flex;
    flex: 1;
    flex-direction: column;
    gap: 2px;
    min-width: 0;
}

.lock-synced-time {
    color: var(--secondary-text-color);
    font-size: 11px;
}

.lock-synced-time.synced {
    color: var(--lcm-success-color);
}

.lock-synced-time.pending {
    color: var(--lcm-warning-color);
}

.lock-synced-time.suspended {
    color: var(--lcm-error-color);
    font-weight: 500;
}

.lock-synced-time.syncing {
    color: var(--lcm-warning-color);
}

.lock-code-field {
    align-items: center;
    display: flex;
    gap: 4px;
}

.lock-code-value {
    color: var(--primary-text-color);
    font-family: var(--lcm-code-font);
    font-size: 13px;
    font-weight: 500;
    letter-spacing: var(--lcm-code-letter-spacing);
}

/* Event row — single click-through row at the bottom of the card that
   opens the more-info dialog for the slot's PIN-used event entity. Sits
   below the content flex container so the gap above provides natural
   separation (no top border needed). */
.event-row {
    align-items: center;
    cursor: pointer;
    display: flex;
    gap: 10px;
    padding: 12px 16px;
}

