/**
 * Shared collapsible section styles.
 */
export const lcmCollapsibleStyles = css`
    .collapsible-section {
        background: var(--lcm-section-bg);
        border-radius: 12px;
        overflow: hidden;
    }

    .collapsible-header {
        align-items: center;
        cursor: pointer;
        display: flex;
        justify-content: space-between;
        padding: 12px 16px;
        user-select: none;
    }

    .collapsible-header:hover {
        background: var(--lcm-section-bg-hover);
    }

    .collapsible-title {
        align-items: center;
        color: var(--secondary-text-color);
        display: flex;
        font-size: var(--lcm-section-header-size);
        font-weight: var(--lcm-section-header-weight);
        gap: 8px;
        letter-spacing: var(--lcm-section-header-spacing);
        text-transform: uppercase;
    }

    .collapsible-badge {
        background: var(--lcm-active-bg);
        border-radius: 10px;
        color: var(--primary-color);
        font-size: var(--lcm-badge-font-size);
        padding: 2px 8px;
    }

    .collapsible-badge.primary {
        background: var(--primary-color);
        color: var(--text-primary-color, #fff);
    }

    .collapsible-badge.warning {
        background: var(--warning-color, #ffa600);
        color: var(--text-primary-color, #fff);
    }

    .collapsible-badge.muted {
        background: var(--lcm-section-bg);
        color: var(--secondary-text-color);
    }

    .collapsible-chevron {
        --mdc-icon-size: 20px;
        color: var(--secondary-text-color);
        transition: transform 0.2s ease;
    }

    .collapsible-content {
        max-height: 0;
        opacity: 0;
        overflow: hidden;
        padding: 0 16px;
        transition:
            max-height 0.3s ease,
            opacity 0.2s ease,
            padding 0.3s ease;
    }

    .collapsible-content.expanded {
        max-height: 500px;
        opacity: 1;
        padding: 0 16px 16px;
    }
`;

/**
 * Shared editable field styles for inline editing.
 */
export const lcmEditableStyles = css`

input.prompt:
You are implementing a design refinement on PR #1116 for the `lock_code_manager` slot card.

**Working directory:** `/Users/raman/projects/lock_code_manager`

**Branch:** `phase2/slot-card-redesign` (currently checked out in the main repo; the worktree was removed, the branch tracks `origin/phase2/slot-card-redesign`)

**Toolchain:** `npm test`, `npm run build`, `prek run --files <paths>`. Vitest baseline 607 tests pass.

**No-commit reminder:** Never stage anything under `docs/superpowers/plans/` or `docs/mockups/`.

# The change

The Conditions section's empty state currently renders the Add affordance only inside the expanded body. The user wants the Add affordance promoted to the collapsed row when there's nothing worth expanding for, on the principle that expansion should only be available when there's content.

**New behavior matrix:**

1. **No condition AND no helpers configured** — render a non-collapsible row that looks like a section header but has NO chevron and NO toggle. The right side shows a `+ Add condition` button. Click → opens the Manage Condition dialog in `add` mode.
2. **No condition AND helpers exist** — render the standard collapsible (helpers ARE content worth expanding for). The `headerExtra` slot becomes the `+ Add condition` button (replacing the `none` muted badge). Body renders just the helpers list — drop the empty-state callout.
3. **Condition exists** — unchanged: collapsible with `_renderConditionsSummary` badge in header (`✓ <name>` / `✗ <name>`), body renders condition block + Manage link + helpers (if any).

# Implementation

## Step 1: Update `_renderConditionsSection` (`ts/slot-card.ts`)

Currently (find it around line 510):

```typescript
private _renderConditionsSection(conditions: SlotCardConditions): TemplateResult {
    const hasEntity = conditions.condition_entity !== undefined;
    const hasHelpers = (this._config?.condition_helpers?.length ?? 0) > 0
        && this._config!.condition_helpers!.some((eid: string) => this._hass?.states[eid]);

    const summary = this._renderConditionsSummary(conditions);
    const body = this._renderConditionsBody(conditions, hasEntity, hasHelpers);

    return this._renderCollapsible(
        'Conditions',
        this._conditionsExpanded,
        this._toggleConditions,
        body,
        summary
    );
}
```

Replace with:

```typescript
private _renderConditionsSection(conditions: SlotCardConditions): TemplateResult {
    const hasEntity = conditions.condition_entity !== undefined;
    const hasHelpers = (this._config?.condition_helpers?.length ?? 0) > 0
        && this._config!.condition_helpers!.some((eid: string) => this._hass?.states[eid]);

    // No condition + no helpers: nothing to expand to. Render a static header
    // row with the Add button on the right; skip the chevron entirely.
    if (!hasEntity && !hasHelpers) {
        return html`
            <div class="collapsible-section">
                <div class="collapsible-header static">
                    <div class="collapsible-title">Conditions</div>
                    ${this._renderAddConditionButton()}
                </div>
            </div>
        `;
    }

    // No condition + helpers exist: collapsible (helpers are content), but the
    // Add affordance is on the collapsed row instead of inside the body.
    const headerExtra = hasEntity
        ? this._renderConditionsSummary(conditions)
        : this._renderAddConditionButton();
    const body = this._renderConditionsBody(conditions, hasEntity, hasHelpers);

    return this._renderCollapsible(
        'Conditions',
        this._conditionsExpanded,
        this._toggleConditions,
        body,
        headerExtra
    );
}

private _renderAddConditionButton(): TemplateResult {
    return html`
        <button
            class="add-condition-btn"
            @click=${(e: Event) => {
                e.stopPropagation();
                this._openConditionDialog('add');
            }}
            aria-label="Add condition"
        >
            <ha-svg-icon .path=${mdiPlus}></ha-svg-icon>
            Add condition
        </button>
    `;
}
```

Add `mdiPlus` to the `@mdi/js` imports at the top of the file.

## Step 2: Update `_renderConditionsBody` to drop the empty-state callout

Find it (around line 540). Currently:

```typescript
private _renderConditionsBody(
    conditions: SlotCardConditions,
    hasEntity: boolean,
    hasHelpers: boolean
): TemplateResult {
    return html`
        ${hasEntity
            ? html`${this._renderConditionBlock(conditions.condition_entity!)}
                  <span class="manage-link" @click=${...}>...Manage condition</span>`
            : html`<div class="empty-state">
                  No condition has been set.<br />
                  <span class="add-link" @click=${...}>+ Add a condition</span>
              </div>`}
        ${hasHelpers ? this._renderHelpers() : nothing}
    `;
}
```

Update to drop the empty-state branch (the Add button is now on the header for that case):

```typescript
private _renderConditionsBody(
    conditions: SlotCardConditions,
    hasEntity: boolean,
    hasHelpers: boolean
): TemplateResult {
    return html`
        ${hasEntity
            ? html`${this._renderConditionBlock(conditions.condition_entity!)}
                  <span
                      class="manage-link"
                      role="button"
                      tabindex="0"
                      aria-label="Manage condition"
                      @click=${() => this._openConditionDialog('manage')}
                      @keydown=${(e: KeyboardEvent) => {
                          if (e.key === 'Enter' || e.key === ' ') {
                              e.preventDefault();
                              this._openConditionDialog('manage');
                          }
                      }}
                  >
                      <ha-svg-icon .path=${mdiCog}></ha-svg-icon>
                      Manage condition
                  </span>`
            : nothing}
        ${hasHelpers ? this._renderHelpers() : nothing}
    `;
}
```

(Preserve whatever existing `manage-link` keyboard accessibility wiring the current code has — copy it verbatim from the existing code; the snippet above is illustrative.)

You can now also delete the `.add-link` and `.empty-state` CSS rules from `slot-card.styles.ts` since they're no longer referenced. Verify with `grep -n "add-link\|empty-state" ts/` first to make sure nothing else uses them.

## Step 3: Add CSS for the Add Condition button + the static-header variant

In `ts/slot-card.styles.ts`, add these rules near the other collapsible-related styles:

```css
/* Add condition button — sits in the headerExtra slot of the Conditions
   section (collapsed row) when no condition is set. Replaces the muted
   "none" badge with a directly-actionable button. */
.add-condition-btn {
    align-items: center;
    background: var(--lcm-section-bg-hover, rgba(127, 127, 127, 0.08));
    border: none;
    border-radius: 12px;
    color: var(--primary-color);
    cursor: pointer;
    display: inline-flex;
    font-family: inherit;
    font-size: 12px;
    font-weight: 600;
    gap: 4px;
    padding: 4px 10px;
}
.add-condition-btn:hover {
    background: var(--primary-color);
    color: var(--text-primary-color, #fff);
}
.add-condition-btn ha-svg-icon {
    --mdc-icon-size: 14px;
}
.add-condition-btn:focus-visible {
    outline: 2px solid var(--primary-color);
    outline-offset: 2px;
}

/* Static (non-collapsible) variant of .collapsible-header used when the
   Conditions section has no content to expand to — no chevron, no hover,
   no toggle handler. Same outer chrome (.collapsible-section) so it
   visually aligns with sibling sections. */
.collapsible-header.static {
    cursor: default;
}
.collapsible-header.static:hover {
    background: transparent;
}
```

The `.collapsible-header` base style (in `shared-styles.ts`) sets `cursor: pointer` and a hover background — the `.static` variant overrides those. Since the chevron is omitted from the markup, no other override needed.

